+fn runtime_hostcall_telemetry_schema_is_versioned() {
+    let schema = load_json(RUNTIME_HOSTCALL_TELEMETRY_SCHEMA_PATH);
+    assert_eq!(
+        schema["properties"]["schema"]["enum"][0], "pi.ext.hostcall_telemetry.v1",
